// LoadDriver loads the seasonDriverStanding's Driver into the .R struct
func (os SeasonDriverStandingSlice) LoadDriver(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	drivers, err := os.Driver(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range drivers {

			if !(o.DriverID == rel.ID) {
				continue
			}

			rel.R.SeasonDriverStandings = append(rel.R.SeasonDriverStandings, o)

			o.R.Driver = rel
			break
		}
	}

	return nil
}

